SELECT date_trunc('month', createddate::timestamp)::date AS month_start, COUNT(*) AS case_cnt
FROM "Case"
WHERE REPLACE(orderitemid__c,'#','') IN (
  SELECT REPLACE(Id,'#','') FROM "Case" c2 LIMIT 0
)
GROUP BY 1;

